class Solution {
    public List<Integer> findSubstring(String s, String[] words) {
        List<Integer> result = new ArrayList<>();
        if (s == null || s.isEmpty() || words == null || words.length == 0) {
            return result;
        }

        int wordCount = words.length;
        int wordLength = words[0].length();
        int totalLength = wordCount * wordLength;

        Map<String, Integer> wordMap = new HashMap<>();
        for (String word : words) {
            wordMap.put(word, wordMap.getOrDefault(word, 0) + 1);
        }

        for (int i = 0; i <= s.length() - totalLength; i++) {
            Map<String, Integer> tempMap = new HashMap<>();
            for (int j = 0; j < wordCount; j++) {
                String substr = s.substring(i + j * wordLength, i + (j + 1) * wordLength);
                if (!wordMap.containsKey(substr)) {
                    break;
                }
                tempMap.put(substr, tempMap.getOrDefault(substr, 0) + 1);
                if (tempMap.get(substr) > wordMap.get(substr)) {
                    break;
                }
                if (j == wordCount - 1) {
                    result.add(i);
                }
            }
        }
        return result;
    }
}
